import{_ as a,c as e,o as i,ag as s}from"./chunks/framework.DD2hp6gW.js";const o="data:image/png;base64,",r="/assets/campaigns-search-toolbar.CbiuviG2.png",n="/assets/campaigns-search-filter.CJ2thd2T.png",l="/assets/campaigns-filter-dropdown.CS8-mecv.png",d="/assets/campaigns-filter-pills.CUpiwLoI.png",g="data:image/png;base64,",c="/assets/campaigns-sort-panel.DhSJ05lW.png",p="/assets/campaigns-table-view.CIxh18pD.png",h="data:image/png;base64,",m="/assets/campaigns-grid-view.DnwYbvD4.png",u="/assets/campaigns-bulk-actions.CgOFkTip.png",C=JSON.parse('{"title":"All Campaigns","description":"","frontmatter":{},"headers":[],"relativePath":"campaigns/index.md","filePath":"campaigns/index.md","lastUpdated":1761262741000}'),A={name:"campaigns/index.md"};function b(f,t,k,w,x,y){return i(),e("div",null,t[0]||(t[0]=[s('<h1 id="all-campaigns" tabindex="-1">All Campaigns <a class="header-anchor" href="#all-campaigns" aria-label="Permalink to &quot;All Campaigns&quot;">​</a></h1><p>The <strong>All Campaigns</strong> page is your central hub for managing and organizing all discount campaigns. View, filter, sort, and perform actions using either a detailed <strong>Table View</strong> or a visual <strong>Grid View</strong>.</p><hr><h2 id="import-export" tabindex="-1">Import &amp; Export <a class="header-anchor" href="#import-export" aria-label="Permalink to &quot;Import &amp; Export&quot;">​</a></h2><p><img src="'+o+'" alt="Import Export Buttons"></p><p>Quickly migrate or backup your campaigns:</p><ul><li><strong>Import:</strong> Upload a CSV file to restore campaigns from another site or backup</li><li><strong>Export:</strong> Download all campaigns as CSV for backup or migration</li></ul><hr><h2 id="toolbar" tabindex="-1">Toolbar <a class="header-anchor" href="#toolbar" aria-label="Permalink to &quot;Toolbar&quot;">​</a></h2><p>The toolbar provides instant search, filtering, and view switching.</p><h3 id="search" tabindex="-1">Search <a class="header-anchor" href="#search" aria-label="Permalink to &quot;Search&quot;">​</a></h3><p><img src="'+r+'" alt="Search Bar"></p><p>Start typing a campaign name to instantly filter results.</p><h3 id="filtering" tabindex="-1">Filtering <a class="header-anchor" href="#filtering" aria-label="Permalink to &quot;Filtering&quot;">​</a></h3><p>Click the filter icon to open advanced filtering options:</p><p><img src="'+n+'" alt="Search with Filter"></p><p><img src="'+l+'" alt="Filter Dropdown"></p><p>Filter by <strong>Status</strong> (Active, Inactive) or <strong>Type</strong> (Scheduled, Quantity, BOGO, etc.).</p><p>Active filters appear as removable pills:</p><p><img src="'+d+'" alt="Active Filter Pills"></p><p>The filter icon shows a badge indicating how many filters are active:</p><p><img src="'+g+'" alt="Filter Badge"></p><h3 id="view-toggle-settings" tabindex="-1">View Toggle &amp; Settings <a class="header-anchor" href="#view-toggle-settings" aria-label="Permalink to &quot;View Toggle &amp; Settings&quot;">​</a></h3><p><img src="'+c+'" alt="Sort Panel"></p><p>Click the gear icon to access display settings:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Options</th></tr></thead><tbody><tr><td><strong>Sort By</strong></td><td>Status, Title, Type, etc.</td></tr><tr><td><strong>Order</strong></td><td>Ascending / Descending</td></tr><tr><td><strong>Items Per Page</strong></td><td>10, 25, 50, 100</td></tr><tr><td><strong>Properties</strong></td><td>Toggle which columns to show</td></tr></tbody></table><hr><h2 id="table-view" tabindex="-1">Table View <a class="header-anchor" href="#table-view" aria-label="Permalink to &quot;Table View&quot;">​</a></h2><p><img src="'+p+'" alt="Campaigns Table View"></p><p>A dense, data-rich list with sortable columns:</p><table tabindex="0"><thead><tr><th>Column</th><th>Description</th></tr></thead><tbody><tr><td><strong>Title</strong></td><td>Campaign name (click to edit)</td></tr><tr><td><strong>Status</strong></td><td>Active/Inactive indicator</td></tr><tr><td><strong>Type</strong></td><td>Scheduled, Quantity, BOGO, etc.</td></tr><tr><td><strong>Target</strong></td><td>All Products, Selected Categories, etc.</td></tr><tr><td><strong>Duration</strong></td><td>Start and end dates</td></tr><tr><td><strong>Usage</strong></td><td>Times applied <em>(hidden by default)</em></td></tr><tr><td><strong>Last Modified</strong></td><td>When last updated <em>(hidden by default)</em></td></tr><tr><td><strong>Actions</strong></td><td>Row action menu</td></tr></tbody></table><h3 id="row-actions" tabindex="-1">Row Actions <a class="header-anchor" href="#row-actions" aria-label="Permalink to &quot;Row Actions&quot;">​</a></h3><p><img src="'+h+'" alt="Row Actions"></p><p>Click the action icons at the end of each row:</p><ul><li><strong>Edit</strong> (pencil) — Open the campaign editor</li><li><strong>Delete</strong> (trash) — Remove the campaign</li><li><strong>Duplicate</strong> (copy) — Create an exact copy</li></ul><p>Or hover over / click the three-dot menu (⋮) to reveal the same options.</p><hr><h2 id="grid-view" tabindex="-1">Grid View <a class="header-anchor" href="#grid-view" aria-label="Permalink to &quot;Grid View&quot;">​</a></h2><p><img src="'+m+'" alt="Campaigns Grid View"></p><p>A visual, card-based layout showing key information at a glance:</p><ul><li><strong>Status Badge</strong> — Color-coded Active/Inactive</li><li><strong>Campaign Name</strong> — Title of the campaign</li><li><strong>Type &amp; Target</strong> — Campaign logic and scope</li><li><strong>Usage</strong> — How many times applied</li><li><strong>Duration</strong> — Start and end dates</li><li><strong>Last Updated</strong> — When last modified</li></ul><hr><h2 id="bulk-actions-pagination" tabindex="-1">Bulk Actions &amp; Pagination <a class="header-anchor" href="#bulk-actions-pagination" aria-label="Permalink to &quot;Bulk Actions &amp; Pagination&quot;">​</a></h2><p>Select multiple campaigns using checkboxes, then use the bulk action bar at the bottom:</p><p><img src="'+u+'" alt="Bulk Actions Bar"></p><ul><li><strong>Delete</strong> — Remove all selected campaigns</li><li><strong>Export</strong> — Download selected as CSV</li></ul><hr><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>Now that you know how to manage your campaigns, explore each campaign type:</p><ul><li><strong><a href="./scheduled-discounts.html">Scheduled Discounts →</a></strong></li><li><strong><a href="./quantity-discounts.html">Quantity Discounts →</a></strong></li><li><strong><a href="./early-bird-discounts.html">Early Bird Discounts →</a></strong></li><li><strong><a href="./bogo-discounts.html">BOGO (Buy X Get X) →</a></strong></li><li><strong><a href="./bogo-advanced-discounts.html">BOGO Advanced (Buy X Get Y) →</a></strong></li><li><strong><a href="./product-in-cart-discounts.html">Product In Cart →</a></strong></li><li><strong><a href="./../core-concepts/conditions.html">Conditions →</a></strong></li></ul>',50)]))}const S=a(A,[["render",b]]);export{C as __pageData,S as default};
